WITH lookup AS (
  SELECT hub, alt_hub, notes FROM nearest_hubs WHERE LOWER(district) = LOWER($1)
),
gap AS (
  INSERT INTO service_gaps (district, region, tenant_slug) VALUES ($1, $2, $3)
  ON CONFLICT (district) DO UPDATE SET request_count = service_gaps.request_count + 1, last_requested = NOW()
  RETURNING 1
)
SELECT * FROM lookup;
-- /* tenancy:patched */

